import{_ as s,c as a,o as n,a4 as l}from"./chunks/framework.HaEZziQ1.js";const e="/FrontEndLearnNotes/assets/CSRF攻击原理.CNznBs-G.jpg",b=JSON.parse('{"title":"网络安全面试题","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端面试相关/网络安全面试题.md","filePath":"Document/前端面试相关/网络安全面试题.md","lastUpdated":1709668918000}'),p={name:"Document/前端面试相关/网络安全面试题.md"},o=l(`<h1 id="网络安全面试题" tabindex="-1">网络安全面试题 <a class="header-anchor" href="#网络安全面试题" aria-label="Permalink to &quot;网络安全面试题&quot;">​</a></h1><h2 id="csrf-和-xss-的网络攻击及防范" tabindex="-1">csrf 和 xss 的网络攻击及防范 <a class="header-anchor" href="#csrf-和-xss-的网络攻击及防范" aria-label="Permalink to &quot;csrf 和 xss 的网络攻击及防范&quot;">​</a></h2><p>参考回答： CSRF：跨站请求伪造，可以理解为攻击者盗用了用户的身份，以用户的名义发送了恶意请求，比如用户登录了一个网站后，立刻在另一个ｔａｂ页面访问量攻击者用来制造攻击的网站，这个网站要求访问刚刚登陆的网站，并发送了一个恶意请求，这时候CSRF 就产生了，比如这个制造攻击的网站使用一张图片，但是这种图片的链接却是可以修改数据库的，这时候攻击者就可以以用户的名义操作这个数据库，防御方式的话：使用验证码，检查 https 头部的 refer，使用 token</p><p>XSS：跨站脚本攻击，是说攻击者通过注入恶意的脚本，在用户浏览网页的时候进行攻击，比如获取 cookie，或者其他用户身份信息，可以分为存储型和反射型，存储型是攻击者输入一些数据并且存储到了数据库中，其他浏览者看到的时候进行攻击，反射型的话不存储在数据库中，往往表现为将攻击代码放在 url 地址的请求参数中，防御的话为 cookie 设置 httpOnly 属性，对用户的输入进行检查，进行特殊字符过滤。</p><h2 id="xss" tabindex="-1">XSS <a class="header-anchor" href="#xss" aria-label="Permalink to &quot;XSS&quot;">​</a></h2><p>涉及⾯试题：什么是 XSS 攻击？如何防范 XSS 攻击？什么是 CSP ？</p><ul><li>XSS 简单点来说，就是攻击者想尽⼀切办法将可以执⾏的代码注⼊到⽹⻚中。</li><li>XSS 可以分为多种类型，但是总体上我认为分为两类：持久型和⾮持久型。</li><li>持久型也就是攻击的代码被服务端写⼊进数据库中，这种攻击危害性很⼤，因为如果⽹站访问量很⼤的话，就会导致⼤量正常访问⻚⾯的⽤户都受到攻击。</li></ul><p>举个例⼦，对于评论功能来说，就得防范持久型 XSS 攻击，因为我可以在评 论中输⼊以下内容</p><ul><li>这种情况如果前后端没有做好防御的话，这段评论就会被存储到数据库中，这样每个打开该⻚⾯的⽤户都会被攻击到。</li><li>⾮持久型相⽐于前者危害就⼩的多了，⼀般通过修改 URL 参数的⽅式加⼊攻击代码，诱导⽤户访问链接从⽽进⾏攻击。</li></ul><p>举个例⼦，如果⻚⾯需要从 URL 中获取某些参数作为内容的话，不经过过滤 就会导致攻击代码被执⾏</p><div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">&lt;!-- http://www.domain.com?name=&lt;script&gt;alert(1)&lt;/script&gt; --&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">&gt;{{name}}&lt;/</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>但是对于这种攻击⽅式来说，如果⽤户使⽤ Chrome 这类浏览器的话，浏览 器就能⾃动帮助⽤户防御攻击。但是我们不能因此就不防御此类攻击了，因为 我不能确保⽤户都使⽤了该类浏览器。</p><h3 id="对于-xss-攻击来说-通常有两种方式可以用来防御" tabindex="-1">对于 XSS 攻击来说，通常有两种⽅式可以⽤来防御 <a class="header-anchor" href="#对于-xss-攻击来说-通常有两种方式可以用来防御" aria-label="Permalink to &quot;对于 XSS 攻击来说，通常有两种⽅式可以⽤来防御&quot;">​</a></h3><h4 id="_1-转义字符" tabindex="-1">1.转义字符 <a class="header-anchor" href="#_1-转义字符" aria-label="Permalink to &quot;1.转义字符&quot;">​</a></h4><p>⾸先，对于⽤户的输⼊应该是永远不信任的。最普遍的做法就是转义输⼊输出 的内容，对于引号、尖括号、斜杠进⾏转义</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> escape</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;font-style:italic;">str</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E06C75;"> str</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> str</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">replace</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">/&amp;/</span><span style="color:#C678DD;">g</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;&amp;amp;&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E06C75;"> str</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> str</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">replace</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">/&lt;/</span><span style="color:#C678DD;">g</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;&amp;lt;&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E06C75;"> str</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> str</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">replace</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">/&gt;/</span><span style="color:#C678DD;">g</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;&amp;gt;&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E06C75;"> str</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> str</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">replace</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">/&quot;/</span><span style="color:#C678DD;">g</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;&amp;quto;&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E06C75;"> str</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> str</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">replace</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">/&#39;/</span><span style="color:#C678DD;">g</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;&amp;#39;&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E06C75;"> str</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> str</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">replace</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">/\`/</span><span style="color:#C678DD;">g</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;&amp;#96;&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E06C75;"> str</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> str</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">replace</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">/</span><span style="color:#56B6C2;">\\/</span><span style="color:#E06C75;">/</span><span style="color:#C678DD;">g</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;&amp;#x2F;&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#C678DD;"> return</span><span style="color:#E06C75;"> str</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>通过转义可以将攻击代码 <code>&lt;script&gt;alert(1)&lt;/script&gt;</code> 变成</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// -&gt; &amp;lt;script&amp;gt;alert(1)&amp;lt;&amp;#x2F;script&amp;gt;</span></span>
<span class="line"><span style="color:#61AFEF;">escape</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;&lt;script&gt;alert(1)&lt;/script&gt;&#39;</span><span style="color:#ABB2BF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>但是对于显示富⽂本来说，显然不能通过上⾯的办法来转义所有字符，因为这 样会把需要的格式也过滤掉。对于这种情况，通常采⽤⽩名单过滤的办法，当 然也可以通过⿊名单过滤，但是考虑到需要过滤的标签和标签属性实在太多， 更加推荐使⽤⽩名单的⽅式</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> xss</span><span style="color:#56B6C2;"> =</span><span style="color:#61AFEF;"> require</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;xss&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#C678DD;">let</span><span style="color:#E06C75;"> html</span><span style="color:#56B6C2;"> =</span><span style="color:#61AFEF;"> xss</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;&lt;h1 id=&quot;title&quot;&gt;XSS Demo&lt;/h1&gt;&lt;script&gt;alert(&quot;xss&quot;);&lt;/script&gt;&#39;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// -&gt; &lt;h1&gt;XSS Demo&lt;/h1&gt;&amp;lt;script&amp;gt;alert(&quot;xss&quot;);&amp;lt;/script&amp;gt;</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">html</span><span style="color:#ABB2BF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>以上示例使⽤了 js-xss 来实现，可以看到在输出中保留了 h1 标签且过滤了 script 标签</p><h4 id="_2-csp" tabindex="-1">2.CSP <a class="header-anchor" href="#_2-csp" aria-label="Permalink to &quot;2.CSP&quot;">​</a></h4><p>CSP 本质上就是建⽴⽩名单，开发者明确告诉浏览器哪些外部资源可以加载 和执⾏。我们只需要配置规则，如何拦截是由浏览器⾃⼰实现的。我们可以通 过这种⽅式来尽量减少 XSS 攻击。</p><p>通常可以通过两种⽅式来开启 CSP：</p><ul><li>设置 HTTP Header 中的 Content-Security-Policy</li><li>设置 meta 标签的⽅式 <code>&lt;meta http-equiv=&quot;Content-Security-Policy&quot;&gt;</code></li></ul><p>这⾥以设置 HTTP Header 来举例</p><h5 id="只允许加载本站资源" tabindex="-1">只允许加载本站资源 <a class="header-anchor" href="#只允许加载本站资源" aria-label="Permalink to &quot;只允许加载本站资源&quot;">​</a></h5><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">Content-Security-Policy:</span><span style="color:#98C379;"> default-src</span><span style="color:#98C379;"> ‘self’</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h5 id="只允许加载-https-协议图片" tabindex="-1">只允许加载 HTTPS 协议图⽚ <a class="header-anchor" href="#只允许加载-https-协议图片" aria-label="Permalink to &quot;只允许加载 HTTPS 协议图⽚&quot;">​</a></h5><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">Content-Security-Policy:</span><span style="color:#98C379;"> img-src</span><span style="color:#98C379;"> https://</span><span style="color:#E5C07B;">*</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h5 id="允许加载任何来源框架" tabindex="-1">允许加载任何来源框架 <a class="header-anchor" href="#允许加载任何来源框架" aria-label="Permalink to &quot;允许加载任何来源框架&quot;">​</a></h5><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">Content-Security-Policy:</span><span style="color:#98C379;"> child-src</span><span style="color:#98C379;"> &#39;none&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>当然可以设置的属性远不⽌这些，你可以通过查阅 ⽂档 的⽅式来学习，这⾥就不过多赘述其他的属性了。对于这种⽅式来说，只要开发者配置了正确的规则，那么即使⽹站存在漏洞，攻击者也不能执⾏它的攻击代码，并且 CSP 的兼容性也不错。</p><p>对于这种⽅式来说，只要开发者配置了正确的规则，那么即使⽹站存在漏洞， 攻击者也不能执⾏它的攻击代码，并且 CSP 的兼容性也不错。</p><h2 id="csrf" tabindex="-1">CSRF <a class="header-anchor" href="#csrf" aria-label="Permalink to &quot;CSRF&quot;">​</a></h2><p>涉及⾯试题：什么是 CSRF 攻击？如何防范 CSRF 攻击？</p><p>CSRF 中⽂名为跨站请求伪造。原理就是攻击者构造出⼀个后端请求地址，诱导⽤户点击或者通过某些途径⾃动发起请求。如果⽤户是在登录状态下的话，后端就以为是⽤户在操作，从⽽进⾏相应的逻辑。</p><p>举个例⼦，假设⽹站中有⼀个通过 GET 请求提交⽤户评论的接⼝，那么攻击者就可以在钓⻥⽹站中加⼊⼀个图⽚，图⽚的地址就是评论接⼝</p><div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">img</span><span style="color:#D19A66;"> src</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;http://www.domain.com/xxx?comment=&#39;attack&#39;&quot;</span><span style="color:#ABB2BF;">/&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>那么你是否会想到使⽤ POST ⽅式提交请求是不是就没有这个问题了呢？其实并不是，使⽤这种⽅式也不是百分百安全的，攻击者同样可以诱导⽤户进⼊某个⻚⾯，在⻚⾯中通过表单提交 POST 请求。</p><h3 id="如何防御" tabindex="-1">如何防御 <a class="header-anchor" href="#如何防御" aria-label="Permalink to &quot;如何防御&quot;">​</a></h3><ul><li>Get 请求不对数据进⾏修改</li><li>不让第三⽅⽹站访问到⽤户 Cookie</li><li>阻⽌第三⽅⽹站请求接⼝</li><li>请求时附带验证信息，⽐如验证码或者 Token</li></ul><h4 id="samesite" tabindex="-1">SameSite <a class="header-anchor" href="#samesite" aria-label="Permalink to &quot;SameSite&quot;">​</a></h4><p>可以对 Cookie 设置 SameSite 属性。该属性表示 Cookie 不随着跨域请 求发送，可以很⼤程度减少 CSRF 的攻击，但是该属性⽬前并不是所有浏览 器都兼容。</p><h4 id="验证-referer" tabindex="-1">验证 Referer <a class="header-anchor" href="#验证-referer" aria-label="Permalink to &quot;验证 Referer&quot;">​</a></h4><p>对于需要防范 CSRF 的请求，我们可以通过验证 Referer 来判断该请求是否为第三⽅⽹站发起的。</p><h4 id="token" tabindex="-1">Token <a class="header-anchor" href="#token" aria-label="Permalink to &quot;Token&quot;">​</a></h4><p>服务器下发⼀个随机 Token ，每次发起请求时将 Token 携带上，服务器验证 Token 是否有效</p><h2 id="安全问题-如-xss-和-csrf" tabindex="-1">安全问题，如 XSS 和 CSRF <a class="header-anchor" href="#安全问题-如-xss-和-csrf" aria-label="Permalink to &quot;安全问题，如 XSS 和 CSRF&quot;">​</a></h2><p>XSS ：跨站脚本攻击，是⼀种⽹站应⽤程序的安全漏洞攻击，是代码注⼊的⼀种。常⻅⽅式是将恶意代码注⼊合法代码⾥隐藏起来，再诱发恶意代码，从⽽进⾏各种各样的⾮法活动</p><p>防范：记住⼀点 “所有⽤户输⼊都是不可信的”，所以得做输⼊过滤和转义</p><p>CSRF ：跨站请求伪造，也称 XSRF ，是⼀种挟制⽤户在当前已登录的 Web 应⽤程序上执⾏⾮本意的操作的攻击⽅法。与 XSS 相⽐， XSS 利⽤的是⽤户对指定⽹站的信任，CSRF 利⽤的是⽹站对⽤户⽹⻚浏览器的信任。</p><p>防范：⽤户操作验证（验证码），额外验证机制（ token 使⽤）等</p><h2 id="为什么要有同源限制" tabindex="-1">为什么要有同源限制？ <a class="header-anchor" href="#为什么要有同源限制" aria-label="Permalink to &quot;为什么要有同源限制？&quot;">​</a></h2><p>同源策略指的是：协议，域名，端⼝相同，同源策略是一种安全协议</p><p>举例说明：⽐如一个⿊客程序，他利用 Iframe 把真正的银⾏登录⻚⾯嵌到他的⻚⾯上，当你使用真实的用户名，密码登录时，他的⻚⾯就可以通过 Javascript 读取到你的表单中 input 中的内容，这样用户名，密码就轻松到⼿了。</p><h2 id="常见的-web-安全及防护原理" tabindex="-1">常见的 web 安全及防护原理 <a class="header-anchor" href="#常见的-web-安全及防护原理" aria-label="Permalink to &quot;常见的 web 安全及防护原理&quot;">​</a></h2><h3 id="sql-注入原理" tabindex="-1">sql 注入原理 <a class="header-anchor" href="#sql-注入原理" aria-label="Permalink to &quot;sql 注入原理&quot;">​</a></h3><p>就是通过把 SQL 命令插⼊到 Web 表单递交或输⼊域名或⻚⾯请求的查询字符串，最终达到欺骗服务器执⾏恶意的 SQL 命令</p><p>总的来说有以下几点：</p><ul><li>永远不要信任用户的输⼊，要对用户的输⼊进⾏校验，可以通过正则表达式，或限制⻓度，对单引号和双 &quot;-&quot; 进⾏转换等</li><li>永远不要使用动态拼装 SQL，可以使用参数化的 SQL 或者直接使用存储过程进⾏数据查询存取</li><li>永远不要使用管理员权限的数据库连接，为每个应用使用单独的权限有限的数据库连接</li><li>不要把机密信息明文存放，请加密或者 hash 掉密码和敏感的信息</li></ul><h3 id="xss-原理及防范" tabindex="-1">XSS 原理及防范 <a class="header-anchor" href="#xss-原理及防范" aria-label="Permalink to &quot;XSS 原理及防范&quot;">​</a></h3><p>Xss(cross-site scripting) 攻击指的是攻击者往 Web ⻚⾯⾥插⼊恶意 html 标签或者 javascript 代码。⽐如：攻击者在论坛中放一个看似安全的链接，骗取用户点击后，窃取 cookie 中的用户私密信息；或者攻击者在论坛中加一个恶意表单，当用户提交表单的时候，却把信息传送到攻击者的服务器中，⽽不是用户原本以为的信任站点</p><h3 id="xss-防范方法" tabindex="-1">XSS 防范方法 <a class="header-anchor" href="#xss-防范方法" aria-label="Permalink to &quot;XSS 防范方法&quot;">​</a></h3><p>⾸先代码⾥对用户输⼊的地方和变量都需要仔细检查⻓度和对 ”&lt;”,”&gt;”,”;”,”’” 等字符做过滤；其次任何内容写到⻚⾯之前都必须加以 encode，避免不小⼼把 html tag 弄出来。这一个层⾯做好，⾄少可以堵住超过一半的 XSS 攻击</p><h3 id="xss-与-csrf-有什么区别吗" tabindex="-1">XSS 与 CSRF 有什么区别吗？ <a class="header-anchor" href="#xss-与-csrf-有什么区别吗" aria-label="Permalink to &quot;XSS 与 CSRF 有什么区别吗？&quot;">​</a></h3><ul><li>XSS 是获取信息，不需要提前知道其他用户⻚⾯的代码和数据包。 CSRF 是代替用户完成指定的动作，需要知道其他用户⻚⾯的代码和数据包。要完成一次 CSRF 攻击，受害者必须依次完成两个步骤</li><li>登录受信任⽹站 A ，并在本地生成 Cookie</li><li>在不登出 A 的情况下，访问危险⽹站 B</li></ul><h3 id="csrf-的防御" tabindex="-1">CSRF 的防御 <a class="header-anchor" href="#csrf-的防御" aria-label="Permalink to &quot;CSRF 的防御&quot;">​</a></h3><ul><li>服务端的 CSRF 方式方法很多样，但总的思想都是一致的，就是在客户端⻚⾯增加伪随机数</li><li>通过验证码的方法</li></ul><h2 id="csrf-1" tabindex="-1">CSRF <a class="header-anchor" href="#csrf-1" aria-label="Permalink to &quot;CSRF&quot;">​</a></h2><h3 id="基本概念和缩写" tabindex="-1">基本概念和缩写 <a class="header-anchor" href="#基本概念和缩写" aria-label="Permalink to &quot;基本概念和缩写&quot;">​</a></h3><p>CSRF，通常称为跨站请求伪造，英文名 Cross-site request forgery 缩写 CSRF</p><h3 id="攻击原理" tabindex="-1">攻击原理 <a class="header-anchor" href="#攻击原理" aria-label="Permalink to &quot;攻击原理&quot;">​</a></h3><p><img src="`+e+`" alt="CSRF攻击原理"></p><h3 id="防御措施" tabindex="-1">防御措施 <a class="header-anchor" href="#防御措施" aria-label="Permalink to &quot;防御措施&quot;">​</a></h3><ul><li>Token 验证</li><li>Referer 验证</li><li>隐藏令牌</li></ul><h2 id="xss-1" tabindex="-1">XSS <a class="header-anchor" href="#xss-1" aria-label="Permalink to &quot;XSS&quot;">​</a></h2><h3 id="基本概念和缩写-1" tabindex="-1">基本概念和缩写 <a class="header-anchor" href="#基本概念和缩写-1" aria-label="Permalink to &quot;基本概念和缩写&quot;">​</a></h3><p>XSS (cross-site scripting 跨域脚本攻击)</p><h3 id="攻击原理-1" tabindex="-1">攻击原理 <a class="header-anchor" href="#攻击原理-1" aria-label="Permalink to &quot;攻击原理&quot;">​</a></h3><p>慕课免费课程：<a href="http://www.imooc.com/learn/812" target="_blank" rel="noreferrer">Web 安全 XSS 攻击防范实例视频教程-慕课网 (imooc.com)</a></p><h3 id="防御措施-1" tabindex="-1">防御措施 <a class="header-anchor" href="#防御措施-1" aria-label="Permalink to &quot;防御措施&quot;">​</a></h3><p>慕课免费课程：<a href="http://www.imooc.com/learn/812" target="_blank" rel="noreferrer">Web 安全 XSS 攻击防范实例视频教程-慕课网 (imooc.com)</a></p><h2 id="iframe点击劫持" tabindex="-1">iframe点击劫持 <a class="header-anchor" href="#iframe点击劫持" aria-label="Permalink to &quot;iframe点击劫持&quot;">​</a></h2><p><strong>涉及⾯试题：什么是点击劫持？如何防范点击劫持？</strong></p><p>点击劫持是⼀种视觉欺骗的攻击⼿段。攻击者将需要攻击的⽹站通过iframe 嵌套的⽅式嵌⼊⾃⼰的⽹⻚中，并将 iframe 设置为透明，在⻚⾯中透出⼀个按钮诱导⽤户点击</p><h3 id="对于这种攻击方式-推荐防御的方法有两种" tabindex="-1">对于这种攻击⽅式，推荐防御的⽅法有两种 <a class="header-anchor" href="#对于这种攻击方式-推荐防御的方法有两种" aria-label="Permalink to &quot;对于这种攻击⽅式，推荐防御的⽅法有两种&quot;">​</a></h3><h4 id="_1-x-frame-options" tabindex="-1">1.X-FRAME-OPTIONS <a class="header-anchor" href="#_1-x-frame-options" aria-label="Permalink to &quot;1.X-FRAME-OPTIONS&quot;">​</a></h4><p>X-FRAME-OPTIONS 是⼀个 HTTP 响应头，在现代浏览器有⼀个很好的⽀ 持。这个 HTTP 响应头 就是为了防御⽤ iframe 嵌套的点击劫持攻击。</p><p>该响应头有三个值可选，分别是DENY ，表示⻚⾯不允许通过 iframe 的⽅式展示SAMEORIGIN ，表示⻚⾯可以在相同域名下通过 iframe 的⽅式展示ALLOW-FROM ，表示⻚⾯可以在指定来源的 iframe 中展示。</p><h4 id="_2-js-防御" tabindex="-1">2.JS 防御 <a class="header-anchor" href="#_2-js-防御" aria-label="Permalink to &quot;2.JS 防御&quot;">​</a></h4><p>对于某些远古浏览器来说，并不能⽀持上⾯的这种⽅式，那我们只有通过 JS的⽅式来防御点击劫持了。</p><div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">head</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;"> &lt;</span><span style="color:#E06C75;">style</span><span style="color:#D19A66;"> id</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;click-jack&quot;</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#E06C75;">     html</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">     	display: </span><span style="color:#D19A66;">none</span><span style="color:#C678DD;"> !important</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">     }</span></span>
<span class="line"><span style="color:#ABB2BF;"> &lt;/</span><span style="color:#E06C75;">style</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">head</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">body</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;"> &lt;</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#C678DD;"> if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">self</span><span style="color:#56B6C2;"> ==</span><span style="color:#E06C75;"> top</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#C678DD;">     var</span><span style="color:#E06C75;"> style</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> document</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">getElementById</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;click-jack&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E5C07B;">     document</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">body</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">removeChild</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">style</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#ABB2BF;"> } </span><span style="color:#C678DD;">else</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;"> 	top</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">location</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> self</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">location</span></span>
<span class="line"><span style="color:#ABB2BF;"> }</span></span>
<span class="line"><span style="color:#ABB2BF;"> &lt;/</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">body</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>以上代码的作⽤就是当通过 iframe 的⽅式加载⻚⾯时，攻击者的⽹⻚直接 不显示所有内容了</p><h2 id="跨域" tabindex="-1">跨域 <a class="header-anchor" href="#跨域" aria-label="Permalink to &quot;跨域&quot;">​</a></h2><p>跨域主要是针对 Javascript 的限制，防⽌恶意的脚本窃取/破坏/滥用用户数据。</p><h3 id="什么是跨域" tabindex="-1">什么是跨域？ <a class="header-anchor" href="#什么是跨域" aria-label="Permalink to &quot;什么是跨域？&quot;">​</a></h3><p>同源的判断三要素是 协议、主机（域名/IP）、端⼝ ，只要三者中任何㇐个不同，就会发生跨域。</p><p>注意，即使是⼆级域名与⼦域名之间，也存在跨域问题。</p><p>PS: IE 并未将端⼝纳⼊检测的范围。</p><h3 id="跨域产生了哪些限制-有哪些疑惑点" tabindex="-1">跨域产生了哪些限制？有哪些疑惑点？ <a class="header-anchor" href="#跨域产生了哪些限制-有哪些疑惑点" aria-label="Permalink to &quot;跨域产生了哪些限制？有哪些疑惑点？&quot;">​</a></h3><p>● 写操作或嵌⼊操作是允许的，读操作是禁⽌的：很奇怪吧？你可以在在⽹站中链接到其他⽹站，或者提交跨域的表单；你也可以嵌⼊跨域的图⽚，视频等 媒体资源，甚⾄嵌⼊跨域的 iframe（前提是 X-Frame-Options 不被设置为 Deny 等值）；但是你不能通过 canvas 跨域图⽚的文件细节。</p><p>● 为什么 form 不被同源策略限制：form 提交㇐个 action 后，其处理过程完全交由浏览器和⽬标服务器，是不能指定脚本回调的。⽽通过 Ajax 发出的请求 是可以获取到响应内容的，这就有极⼤⻛险，所以浏览器同源策略限制了跨域 Ajax 和 Fetch。但是，这也不是说 form 就是安全的，诱骗表单或 XSS 注⼊ 的恶意表单也是危险性很⾼的。</p><p>● canvas 操作图⽚的跨域： ● XMLHTTPRequest：⽆法跨域请求，这个是遇到最多的。 ● preflight（预检）： ● Cookie：出于安全考虑，⽆法跨域读取或设置 cookie（⽆论是从服务端还是客户端）。只能通过将 cookie 的 domain 设置为㇐个⽗域名来达到⽗域名下 站点共享该 cookie 的⽬的。</p><h3 id="如何解决跨域问题" tabindex="-1">如何解决跨域问题？ <a class="header-anchor" href="#如何解决跨域问题" aria-label="Permalink to &quot;如何解决跨域问题？&quot;">​</a></h3><p>● jsonp ● CORS ● nginx 反向代理 ● nodejs 服务代理</p><h3 id="同源和同站" tabindex="-1">同源和同站 <a class="header-anchor" href="#同源和同站" aria-label="Permalink to &quot;同源和同站&quot;">​</a></h3><p>Same Origin 和 Same Site 的判断依据。TLD 和 eTLD。</p><p>点击劫持 Click Jacking</p><p>⿊客通过㇐个 iframe 嵌套了⽬标⽹站，并通过㇐些 opacity 等技巧，在最上层覆盖㇐些恶意⽹站的链接，诱骗用户点击。用户以为⾃⼰访问的是百度，其实是㇐个假百度（⿊客的域名进去的，但是用户没注意域名，只看到界⾯是百度）。</p><p>解决方案：HTTP headers 设置 X-FRAME-OPTIONS，用 deny 或者 sameorigin 是⽐较安全的，或者通过 allow-from 指定 URI ⽩名单。</p><h3 id="中间人攻击" tabindex="-1">中间人攻击 <a class="header-anchor" href="#中间人攻击" aria-label="Permalink to &quot;中间人攻击&quot;">​</a></h3><p>Man-in-the-middle attack <a href="https://developer.mozilla.org/en-US/docs/Glossary/MitM" target="_blank" rel="noreferrer">https://developer.mozilla.org/en-US/docs/Glossary/MitM</a> ，通信过程被⿊客劫持，就像邮递员可能篡改邮件㇐样。</p><p>预防中间⼈攻击：使用 HTTPS；用户认证信息和 IP 做绑定。</p><h3 id="什么是-xss-攻击" tabindex="-1">什么是 XSS 攻击？ <a class="header-anchor" href="#什么是-xss-攻击" aria-label="Permalink to &quot;什么是 XSS 攻击？&quot;">​</a></h3><p>XSS 是 Crossing-Site-Scripting，也就是跨站脚本攻击，指的是⿊客恶意在⽬标⽹站植⼊㇐段脚本，用于窃取用户信息和伪装成用户，甚⾄执⾏其他恶意⾏ 为。常发生于未对用户输⼊做校验和未对 innerHTML 做过滤的情况。</p><h3 id="xss-防御手段" tabindex="-1">XSS 防御⼿段 <a class="header-anchor" href="#xss-防御手段" aria-label="Permalink to &quot;XSS 防御⼿段&quot;">​</a></h3><p>● Set-Cookie 增加 HttpOnly 和 Secure 设置 ● Set-Cookie 增加 SameSite 约束 ● 不使用 Cookie 这种⾃动携带的身份验证⼿段，改用 JWT 等⾃定义 Request Header 的方案。 ● CSRF Token ● 关键业务用验证码等方式强制校验。</p>`,118),r=[o];function t(c,i,d,h,B,y){return n(),a("div",null,r)}const m=s(p,[["render",t]]);export{b as __pageData,m as default};
